import React, { useState, useEffect } from 'react';
import { partnerService } from '../services/api';
import { ShoppingCart, TrendingUp, DollarSign, Award } from 'lucide-react';

const fmt = (n) => new Intl.NumberFormat('en-IN', { style: 'currency', currency: 'INR', minimumFractionDigits: 2 }).format(n || 0);

function PartnerDashboard() {
  const [stats, setStats]   = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError]   = useState('');

  useEffect(() => { load(); }, []);

  const load = async () => {
    try {
      setLoading(true);
      const r = await partnerService.getDashboard();
      setStats(r.data);
      setError('');
    } catch {
      setError('Failed to load dashboard');
      setStats({ totalSales: 0, totalRevenue: 0, totalCommission: 0, paidCommission: 0 });
    } finally { setLoading(false); }
  };

  if (loading) return <div style={{ display:'flex', justifyContent:'center', alignItems:'center', minHeight:'100vh', color:'#64748b' }}>Loading dashboard...</div>;

  const cards = [
    { label: 'Total Sales',       value: stats?.totalSales ?? 0,        icon: ShoppingCart, bg: '#dbeafe', color: '#2563eb', num: true },
    { label: 'Total Revenue',     value: fmt(stats?.totalRevenue),       icon: TrendingUp,   bg: '#dcfce7', color: '#16a34a' },
    { label: 'Total Commission',  value: fmt(stats?.totalCommission),    icon: DollarSign,   bg: '#fef3c7', color: '#d97706' },
    { label: 'Paid Commission',   value: fmt(stats?.paidCommission),     icon: Award,        bg: '#ede9fe', color: '#7c3aed' },
  ];

  return (
    <div style={{ padding: '2rem', background: '#f1f5f9', minHeight: '100vh' }}>
      <h1 style={{ fontSize: '2rem', fontWeight: '700', color: '#1e293b', marginBottom: '0.25rem' }}>Partner Dashboard</h1>
      <p style={{ color: '#64748b', marginBottom: '2rem' }}>Overview of your sales performance</p>

      {error && (
        <div style={{ background: '#fef2f2', border: '1px solid #fecaca', color: '#dc2626', padding: '0.875rem 1rem', borderRadius: '8px', marginBottom: '1.5rem' }}>{error}</div>
      )}

      {/* Stat Cards */}
      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(220px, 1fr))', gap: '1.25rem' }}>
        {cards.map(c => (
          <div key={c.label} style={{ background: 'white', borderRadius: '12px', padding: '1.5rem', boxShadow: '0 1px 3px rgba(0,0,0,0.07)', display: 'flex', alignItems: 'center', gap: '1rem' }}>
            <div style={{ width: '52px', height: '52px', borderRadius: '12px', background: c.bg, display: 'flex', alignItems: 'center', justifyContent: 'center', flexShrink: 0 }}>
              <c.icon size={24} color={c.color} />
            </div>
            <div>
              <p style={{ fontSize: '0.8rem', color: '#94a3b8', margin: '0 0 0.35rem', fontWeight: '500' }}>{c.label}</p>
              <p style={{ fontSize: c.num ? '2rem' : '1.35rem', fontWeight: '700', color: '#1e293b', margin: 0 }}>{c.value}</p>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
}

export default PartnerDashboard;
